import React, { useState, useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { Row, Col, Card, Table, Empty, Spin, Modal, Select, Button } from 'antd';
import { UploadOutlined, CloseOutlined } from '@ant-design/icons';
import FilterBar from './component/FilterBar';
import { getFeeleaksconciliation } from '../../redux/reconcilePayment/actionCreator';
import { exportProfitData } from '../../redux/dashboard/actionCreator';
import { PageHeader } from '../../components/page-headers/page-headers';

export default function FeeLeaks() {
  const dispatch = useDispatch();
  const [uploadModal, setUploadModal] = useState(false);
  const [exportType, setExportType] = useState('All Fees');
  useEffect(() => {
    const handler = (e) => {
      if (e.detail === 'export') {
        setUploadModal(true);
      }
    };

    window.addEventListener('headerAction', handler);

    return () => {
      window.removeEventListener('headerAction', handler);
    };
  }, []);

  const payload = {
    filters: {
      method: 'show',
      function_type: 'fee_waiver_order',
      filters: {
        channel: {
          IN: ['Amazon-India', 'Flipkart', 'Jiomart', 'Meesho', 'Myntra', 'Snapdeal'],
        },
        fromDate: '2026-03-31T18:30:00Z',
        toDate: '2026-04-30T18:29:59Z',
      },
      pagination: {
        pageNo: 0,
        pageSize: 25,
      },
      sort: {
        orderdate: -1,
      },
    },
  };

  useEffect(() => {
    dispatch(getFeeleaksconciliation(payload));
  }, []);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setTimeout(() => setLoading(false), 800);
  }, []);
  const varianceSummaryColumns = [
    { title: 'Channel', dataIndex: 'channel' },
    { title: 'Fee Type', dataIndex: 'feeType' },
    { title: 'Order Count', dataIndex: 'orderCount', align: 'right' },
    { title: 'SKU Count', dataIndex: 'skuCount', align: 'right' },
    { title: 'Received Fees', dataIndex: 'received', align: 'right' },
    { title: 'Calculated Fees', dataIndex: 'calculated', align: 'right' },
    { title: 'Variance', dataIndex: 'variance', align: 'right' },
  ];

  const varianceDetailColumns = [
    { title: 'Channel', dataIndex: 'channel' },
    { title: 'Order ID', dataIndex: 'orderId' },
    { title: 'Order Date', dataIndex: 'orderDate', sorter: true },
    { title: 'SKU', dataIndex: 'sku' },
    { title: 'Product ID', dataIndex: 'productId' },
    { title: 'Fees Type', dataIndex: 'feesType' },
    {
      title: 'Recon type',
      dataIndex: 'reconType',
      filters: [
        { text: 'Select All', value: 'ALL' },
        { text: 'Manual', value: 'Manual' },
        { text: 'FeeAuto', value: 'FeeAuto' },
        { text: 'FeeRecon', value: 'FeeRecon' },
      ],
      onFilter: (value, record) => {
        if (value === 'ALL') return true;
        return record.reconType === value;
      },
    },
    { title: 'Received Fees', dataIndex: 'receivedFees', sorter: true },
    { title: 'Calculated Fees', dataIndex: 'calculatedFees', sorter: true },
    { title: 'Variance', dataIndex: 'variance', sorter: true },
  ];

  const PageRoutes = [
    {
      path: 'index',
      breadcrumbName: 'Reconcile',
    },
    {
      path: '',
      breadcrumbName: 'Fee Leaks',
    },
  ];
  const handleApply = () => {
    setLoading(true);

    setTimeout(() => {
      setLoading(false);
    }, 800);
  };
  const handleClear = () => {
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
    }, 800);
  };

  const handleExport = () => {
    const exportPayload = {
      params: {
        filters: {
          channel: {
            IN: ['Amazon-India', 'Flipkart', 'Jiomart', 'Meesho', 'Myntra', 'Snapdeal'],
          },
          fromDate: '2026-04-30T18:30:00Z',
          toDate: '2026-05-31T18:29:59Z',
        },
      },
      reportType: 'fee_waiver_order',
      email: 'bhavnaaprostore@gmail.com',
    };

    dispatch(exportProfitData(exportPayload));

    setUploadModal(false);
  };

  return (
    <>
      <PageHeader
        routes={PageRoutes}
        title="Fees Leaks Recon"
        className="flex  justify-between items-center px-8 xl:px-[15px] pt-2 pb-6 sm:pb-[30px] bg-transparent sm:flex-col"
      />
      <main className="min-h-[715px] lg:min-h-[580px] flex-1 h-auto px-8 xl:px-[15px] pb-[30px] bg-transparent">
        <FilterBar onApply={handleApply} onClear={handleClear} />

        <Spin spinning={loading} size="large">
          <Row gutter={[16, 16]}>
            {/* LEFT TABLE */}
            <Col xs={24} sm={24} md={24} lg={18}>
              <Card title="Variance Table" bordered={false}>
                <Table
                  columns={varianceSummaryColumns}
                  dataSource={[]}
                  pagination={false}
                  scroll={{ x: true }}
                  locale={{
                    emptyText: <Empty description="No data" />,
                  }}
                  summary={() => (
                    <Table.Summary.Row className="bg-blue-50 font-medium">
                      <Table.Summary.Cell>Total</Table.Summary.Cell>
                      <Table.Summary.Cell />
                      <Table.Summary.Cell align="right">0</Table.Summary.Cell>
                      <Table.Summary.Cell align="right">0</Table.Summary.Cell>
                      <Table.Summary.Cell align="right">₹0</Table.Summary.Cell>
                      <Table.Summary.Cell align="right">₹0</Table.Summary.Cell>
                      <Table.Summary.Cell align="right">₹0</Table.Summary.Cell>
                    </Table.Summary.Row>
                  )}
                />
              </Card>
            </Col>

            {/* RIGHT CARD */}
            <Col xs={24} sm={24} md={24} lg={6}>
              <Card title="Variance" bordered={false} className="h-full" />
            </Col>
          </Row>

          {/* BOTTOM TABLE */}
          <Row gutter={[16, 16]} className="mt-4">
            <Col span={24}>
              <Card bordered={false}>
                <Table
                  columns={varianceDetailColumns}
                  dataSource={[]}
                  scroll={{ x: true }}
                  locale={{
                    emptyText: <Empty description="No data" />,
                  }}
                />
              </Card>
            </Col>
          </Row>
        </Spin>
      </main>
      <Modal
        open={uploadModal}
        footer={null}
        closable={false}
        centered
        width={540}
        onCancel={() => setUploadModal(false)}
      >
        <div className="relative">
          {/* CLOSE ICON */}
          <button
            type="button"
            onClick={() => setUploadModal(false)}
            className="absolute right-0 top-0 text-gray-400 hover:text-gray-600"
          >
            <CloseOutlined />
          </button>

          {/* TITLE */}
          <h2 className="text-[20px] font-semibold text-[#1f2937] mb-5">Recon Exports</h2>

          {/* CONTENT */}
          <div className="flex items-center gap-4">
            <Select
              value={exportType}
              onChange={setExportType}
              style={{
                width: '100%',
                height: 42,
              }}
              options={[
                {
                  label: 'All Fees',
                  value: 'All Fees',
                },
                {
                  label: 'Rules Uploaded',
                  value: 'Rule Uploaded',
                },
                {
                  label: 'Amazon-India (All fees)',
                  value: 'Amazon-India (All fees)',
                },
                {
                  label: 'Amazon-India (Shipping fees)',
                  value: 'Amazon-India (Shipping fees)',
                },
                {
                  label: 'Flipkart',
                  value: 'Flipkart',
                },
                {
                  label: 'Myntra',
                  value: 'Myntra',
                },
                {
                  label: 'Jiomart',
                  value: 'Jiomart',
                },
                {
                  label: 'Meesho',
                  value: 'Meesho',
                },
                {
                  label: 'Snapdeal',
                  Index: 'Snapdeal',
                },
              ]}
            />

            <Button
              type="primary"
              icon={<UploadOutlined />}
              className="!h-[42px] px-5 rounded-md"
              onClick={handleExport}
            >
              Export
            </Button>
          </div>
        </div>
      </Modal>
    </>
  );
}
